/**
 * validation_chat.js
 * --------------------
 * Drives the Step 2 "chatbot-style" document validation screen.
 *
 * Design: the full set of clarifying questions is generated by ONE
 * Gemini call at upload time (see services/ai_extraction.py) and passed
 * into this page as window.CLARIFICATION_QA. This script does NOT call
 * the AI again per answer -- it simply reveals questions one at a time
 * in a chat-like UI and collects the user's typed answers, then submits
 * all of them together when the user clicks Continue. This keeps the
 * wizard to exactly one AI call per uploaded document (see the free-tier
 * rate-limit discussion in the README) while still presenting a genuine
 * conversational back-and-forth to the user.
 */

document.addEventListener("DOMContentLoaded", () => {
    const factoryId = document.getElementById("app-data").dataset.factoryId;
    const chatWindow = document.getElementById("chatWindow");
    const inputRow = document.getElementById("chatInputRow");
    const answerInput = document.getElementById("chatAnswerInput");
    const sendBtn = document.getElementById("chatSendBtn");
    const continueBtnRow = document.getElementById("continueBtnRow");
    const continueBtn = document.getElementById("continueBtn");

    const questions = (window.CLARIFICATION_QA || []).map((qa) => qa.question);
    const answers = (window.CLARIFICATION_QA || []).map((qa) => qa.answer || "");
    let currentIndex = 0;

    function addBubble(text, sender) {
        // sender is "bot" or "user"
        const bubble = document.createElement("div");
        bubble.className = `chat-bubble chat-bubble-${sender}`;
        bubble.textContent = text;
        chatWindow.appendChild(bubble);
        chatWindow.scrollTop = chatWindow.scrollHeight;
    }

    function askCurrentQuestion() {
        if (currentIndex < questions.length) {
            addBubble(questions[currentIndex], "bot");
        } else {
            finishChat();
        }
    }

    function finishChat() {
        addBubble("Thanks — that covers everything I needed to ask. Click Continue when you're ready.", "bot");
        inputRow.classList.add("d-none");
        continueBtnRow.style.setProperty("display", "flex", "important");
    }

    function submitAnswer() {
        const text = answerInput.value.trim();
        if (!text) return;
        addBubble(text, "user");
        answers[currentIndex] = text;
        currentIndex += 1;
        answerInput.value = "";
        // Small delay so the bot's next question doesn't appear instantly
        // in the same frame as the user's message -- reads more like a
        // real conversation.
        setTimeout(askCurrentQuestion, 300);
    }

    sendBtn.addEventListener("click", submitAnswer);
    answerInput.addEventListener("keydown", (e) => {
        if (e.key === "Enter") {
            e.preventDefault();
            submitAnswer();
        }
    });

    continueBtn.addEventListener("click", async () => {
        continueBtn.disabled = true;
        continueBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Saving…';
        try {
            const response = await fetch(`/factory/${factoryId}/validate`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ answers }),
            });
            const result = await response.json();
            if (result.success) {
                window.location.href = result.redirect || window.SENSORS_URL;
            } else {
                alert("Could not save your answers. Please try again.");
                continueBtn.disabled = false;
                continueBtn.innerHTML = 'Continue to Sensors <i class="bi bi-arrow-right"></i>';
            }
        } catch (err) {
            alert("Network error while saving your answers. Please try again.");
            console.error(err);
            continueBtn.disabled = false;
            continueBtn.innerHTML = 'Continue to Sensors <i class="bi bi-arrow-right"></i>';
        }
    });

    // --- Kick off the conversation ---------------------------------------
    if (questions.length === 0) {
        addBubble("Your document looks complete — I don't have any follow-up questions.", "bot");
        finishChat();
    } else {
        addBubble(
            "I reviewed your document. I have a few follow-up questions to help correlate risk " +
            "signals across shifts, maintenance, and sensor coverage:",
            "bot"
        );
        askCurrentQuestion();
    }
});
